import Resource from '@/api/resource';
import request from "@/utils/request.js";

class BasesResource extends Resource {
  constructor() {
    super('publico/bases');
  }

    getBases(id_sector) {
    return request({
      url: '/publico/sectores/' + id_sector + '/bases',
      method: 'get'
    })
  }

  getRonderosByBase(query) {
    return request({
      url: '/publico/bases/ronderos',
      method: 'get',
      params: query
    })
  }
  getBasesPorDistrito(distrito_id) {
    console.log(' getBasesPorDistrito llamado con distrito_id:', distrito_id);
    return request({
      url: `/publico/bases/distrito/${distrito_id}/bases`,
      method: 'get'
    })
  }
}

export { BasesResource as default }

import Resource from '@/api/resource';
import request from "@/utils/request.js";

class BasesResource extends Resource {
  constructor() {
    super('publico/bases');
  }

    getBases(id_sector) {
    return request({
      url: '/publico/sectores/' + id_sector + '/bases',
      method: 'get'
    })
  }

  getRonderosByBase(query) {
    return request({
      url: '/publico/bases/ronderos',
      method: 'get',
      params: query
    })
  }
  getBasesPorDistrito(distrito_id) {
    console.log(' getBasesPorDistrito llamado con distrito_id:', distrito_id);
    return request({
      url: `/publico/bases/distrito/${distrito_id}/bases`,
      method: 'get'
    })
  }

  eliminarMasivo(payload) {
    return request({
      url: '/publico/bases/eliminar-masivo',
      method: 'post',
      data: payload,
    })
  }
}

export { BasesResource as default }

import { fileURLToPath, URL } from 'node:url'

import { defineConfig } from 'vite'
import vue from '@vitejs/plugin-vue'
import svgLoader from 'vite-svg-loader'

// https://vitejs.dev/config/
export default defineConfig({
  plugins: [vue(), svgLoader()],
  resolve: {
    alias: {
      '@': fileURLToPath(new URL('./src', import.meta.url))
    }
  }
})

import { fileURLToPath, URL } from 'node:url'

import { defineConfig } from 'vite'
import vue from '@vitejs/plugin-vue'
import svgLoader from 'vite-svg-loader'

// https://vitejs.dev/config/
export default defineConfig({
  plugins: [vue(), svgLoader()],
  resolve: {
    alias: {
      '@': fileURLToPath(new URL('./src', import.meta.url))
    }
  },
  build: {
    outDir: 'dist',
    sourcemap: false,
    minify: 'terser',
    chunkSizeWarningLimit: 1000
  },
  server: {
    proxy: {
      '/api': {
        target: 'http://localhost:8000',
        changeOrigin: true,
        rewrite: (path) => path.replace(/^\/api/, '/api')
      }
    }
  }
})
